import React, { useState, useEffect, useRef } from 'react';

interface Skill {
  name: string;
  level: number; // 0-100
}

interface SkillGroupProps {
  title: string;
  icon: string;
  gradient: string;
  accentColor: string;
  skills: Skill[];
}

const SkillGroup: React.FC<SkillGroupProps> = ({ title, icon, gradient, accentColor, skills }) => {
  const [animated, setAnimated] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => setAnimated(true), 200);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div ref={ref} style={{
      background: '#fff',
      border: '2px solid #c0c0c0',
      borderTop: '2px solid #ffffff',
      borderLeft: '2px solid #ffffff',
      borderRight: '2px solid #808080',
      borderBottom: '2px solid #808080',
      boxShadow: '3px 3px 0 #808080',
      overflow: 'hidden',
      marginBottom: 4,
    }}>
      {/* Gradient header — modern touch */}
      <div style={{
        background: gradient,
        padding: '10px 14px',
        display: 'flex',
        alignItems: 'center',
        gap: 10,
        position: 'relative',
        overflow: 'hidden',
      }}>
        {/* Subtle shine overlay */}
        <div style={{
          position: 'absolute', top: 0, left: 0, right: 0,
          height: '50%',
          background: 'rgba(255,255,255,0.12)',
          pointerEvents: 'none',
        }} />
        {/* Classic Win98 icon box */}
        <div style={{
          width: 28, height: 28,
          background: 'rgba(255,255,255,0.2)',
          border: '1px solid rgba(255,255,255,0.4)',
          borderTop: '1px solid rgba(255,255,255,0.6)',
          borderLeft: '1px solid rgba(255,255,255,0.6)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 16, flexShrink: 0,
        }}>{icon}</div>
        <span style={{
          color: '#fff', fontWeight: 'bold', fontSize: 12,
          letterSpacing: 0.5, textShadow: '0 1px 3px rgba(0,0,0,0.4)',
        }}>{title}</span>
      </div>

      {/* Skills with progress bars */}
      <div style={{ padding: '10px 14px', background: '#f4f4f4' }}>
        {skills.map((skill, i) => (
          <div key={i} style={{ marginBottom: i < skills.length - 1 ? 8 : 0 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
              <span style={{ fontSize: 11, fontWeight: 'bold', color: '#222' }}>{skill.name}</span>
              <span style={{ fontSize: 10, color: '#666' }}>{skill.level}%</span>
            </div>
            {/* Win98-style inset track */}
            <div style={{
              height: 10,
              background: '#c0c0c0',
              borderTop: '1px solid #808080',
              borderLeft: '1px solid #808080',
              borderRight: '1px solid #fff',
              borderBottom: '1px solid #fff',
              position: 'relative',
              overflow: 'hidden',
            }}>
              {/* Modern gradient fill */}
              <div style={{
                position: 'absolute', top: 0, left: 0, bottom: 0,
                width: animated ? `${skill.level}%` : '0%',
                background: `linear-gradient(90deg, ${accentColor}cc, ${accentColor})`,
                transition: `width ${0.6 + i * 0.1}s cubic-bezier(0.4,0,0.2,1)`,
                boxShadow: `inset 0 1px 0 rgba(255,255,255,0.3)`,
              }} />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const groups: SkillGroupProps[] = [
  {
    icon: '☁️', title: 'Cloud Platforms',
    gradient: 'linear-gradient(135deg, #0050a0, #0078d4)',
    accentColor: '#0078d4',
    skills: [
      { name: 'AWS Cloud Practitioner', level: 85 },
      { name: 'Azure AZ-104 Admin', level: 88 },
      { name: 'Azure AZ-900 Fundamentals', level: 95 },
      { name: 'Microsoft Entra ID', level: 82 },
    ],
  },
  {
    icon: '🔒', title: 'Security & Compliance',
    gradient: 'linear-gradient(135deg, #8b0000, #c23b22)',
    accentColor: '#c23b22',
    skills: [
      { name: 'ISC2 Certified in Cybersecurity', level: 80 },
      { name: 'Microsoft Defender', level: 85 },
      { name: 'Security Incident Response', level: 78 },
      { name: 'Microsoft Purview', level: 75 },
    ],
  },
  {
    icon: '💻', title: 'Endpoint & Device Mgmt',
    gradient: 'linear-gradient(135deg, #1a5c1a, #107c10)',
    accentColor: '#107c10',
    skills: [
      { name: 'Microsoft Intune', level: 90 },
      { name: 'SCCM', level: 88 },
      { name: 'Knox Management', level: 75 },
      { name: 'Flexera Snow', level: 80 },
    ],
  },
  {
    icon: '📊', title: 'Microsoft 365 & Monitoring',
    gradient: 'linear-gradient(135deg, #a83200, #d83b01)',
    accentColor: '#d83b01',
    skills: [
      { name: 'Teams / Exchange Admin', level: 92 },
      { name: 'AppDynamics', level: 78 },
      { name: 'Zscaler ELK', level: 74 },
      { name: 'Thousand Eyes', level: 72 },
    ],
  },
  {
    icon: '🏢', title: 'Business Applications',
    gradient: 'linear-gradient(135deg, #3d1a78, #5c2d91)',
    accentColor: '#5c2d91',
    skills: [
      { name: 'Microsoft FinOps', level: 85 },
      { name: 'Dynamics 365 Retail', level: 82 },
      { name: 'SAP C/4HANA', level: 70 },
      { name: 'EFTPOS / POS Systems', level: 88 },
    ],
  },
  {
    icon: '⚙️', title: 'Scripting & Automation',
    gradient: 'linear-gradient(135deg, #004a59, #005b70)',
    accentColor: '#005b70',
    skills: [
      { name: 'PowerShell', level: 82 },
      { name: 'Active Directory', level: 90 },
      { name: 'ITIL Service Management', level: 85 },
      { name: 'Network Configuration', level: 78 },
    ],
  },
];

const Skills: React.FC = () => (
  <div style={{ padding: '20px 24px', overflowY: 'auto' }}>

    {/* Header — classic Win98 title bar style with modern accent */}
    <div style={{
      marginBottom: 20,
      paddingBottom: 12,
      borderBottom: '2px solid',
      borderImage: 'linear-gradient(90deg, #000080, #1084d0, transparent) 1',
      display: 'flex',
      alignItems: 'flex-end',
      justifyContent: 'space-between',
    }}>
      <div>
        <h2 style={{ fontSize: 20, color: '#000080', marginBottom: 2, letterSpacing: 0.3 }}>
          Technical Skills &amp; Certifications
        </h2>
        <p style={{ fontSize: 10, color: '#888', margin: 0 }}>
          Hover over skill bars · {groups.reduce((a, g) => a + g.skills.length, 0)} skills across {groups.length} areas
        </p>
      </div>
      {/* Win98-style raised badge */}
      <div style={{
        padding: '3px 10px',
        background: '#c0c0c0',
        borderTop: '1px solid #fff',
        borderLeft: '1px solid #fff',
        borderRight: '1px solid #808080',
        borderBottom: '1px solid #808080',
        fontSize: 10,
        color: '#000080',
        fontWeight: 'bold',
        letterSpacing: 1,
      }}>
        IT PROFESSIONAL
      </div>
    </div>

    {/* 2-col grid */}
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 }}>
      {groups.map(g => <SkillGroup key={g.title} {...g} />)}
    </div>

  </div>
);

export default Skills;
